import { useState, useEffect, useCallback } from 'react';

// ตัวช่วยเช็ค LocalStorage เผื่อเก็บ Token
const STORAGE_KEY = 'sms_simulator_device';

export function useDevice() {
    const [phoneNumber, setPhoneNumber] = useState('');
    const [token, setToken] = useState('');
    const [isLoading, setIsLoading] = useState(true);

    const generateDevice = async () => {
        setIsLoading(true);
        try {
            const res = await fetch('/api/device/new', { method: 'POST' });
            const data = await res.json();
            if (data.status === 'success') {
                setPhoneNumber(data.data.phoneNumber);
                setToken(data.data.token);
                localStorage.setItem(STORAGE_KEY, JSON.stringify(data.data));
            }
        } catch (e) {
            console.error('Failed to generate device', e);
        } finally {
            setIsLoading(false);
        }
    };

    const registerDevice = async (newPhoneNumber: string) => {
        setIsLoading(true);
        try {
            const res = await fetch('/api/device/register', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ phoneNumber: newPhoneNumber })
            });
            const data = await res.json();
            if (data.status === 'success') {
                setPhoneNumber(data.data.phoneNumber);
                setToken(data.data.token);
                localStorage.setItem(STORAGE_KEY, JSON.stringify(data.data));
                return true;
            }
        } catch (e) {
            console.error('Failed to register device', e);
        } finally {
            setIsLoading(false);
        }
        return false;
    };

    const resetDevice = () => {
        localStorage.removeItem(STORAGE_KEY);
        setPhoneNumber('');
        setToken('');
    };

    useEffect(() => {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setPhoneNumber(parsed.phoneNumber);
                setToken(parsed.token);
                setIsLoading(false);
            } catch (e) {
                // ถ้าพังให้ล้างออกและแสดงหน้าให้กรอกใหม่
                localStorage.removeItem(STORAGE_KEY);
                setIsLoading(false);
            }
        } else {
            // ไม่ต้อง Gen ใหม่แล้ว ให้ UI โชว์ฟอร์มกรอก
            setIsLoading(false);
        }
    }, []);

    return { phoneNumber, token, isLoading, generateDevice, registerDevice, resetDevice };
}

export function useMessages(token: string) {
    const [messages, setMessages] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(false);

    const fetchMessages = useCallback(async () => {
        if (!token) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/messages?token=${token}`);
            const data = await res.json();
            if (data.status === 'success') {
                setMessages(data.data.messages);
            }
        } catch (e) {
            console.error('Failed to fetch messages', e);
        } finally {
            setIsLoading(false);
        }
    }, [token]);

    useEffect(() => {
        fetchMessages();
        // จำลองลักษณะ Realtime ด้วยการ Polling ทุกๆ 3 วินาที
        const interval = setInterval(fetchMessages, 3000);
        return () => clearInterval(interval);
    }, [fetchMessages]);

    return { messages, isLoading, refresh: fetchMessages };
}
